(() => {
  if (window.__repairMockInstalled) return { installed: true }

  const userState = {
    language: 'zh',
    isLogin: true,
    isLock: false,
    lockPassword: '',
    info: {
      userId: 1,
      userName: 'admin',
      nickName: 'admin',
      deptId: 1,
      roles: ['R_SUPER']
    },
    searchHistory: [],
    accessToken: 'mock-token',
    refreshToken: 'mock-refresh-token',
    roles: ['R_SUPER'],
    permissions: ['*:*:*']
  }

  const repairRoutes = [{
    path: '/asset',
    name: 'Asset',
    component: 'Layout',
    meta: { title: 'Asset' },
    children: [
      { path: 'repair', name: 'AssetRepair', component: '/asset/repair/index', meta: { title: 'Repair', keepAlive: true } },
      { path: 'repair/create', name: 'AssetRepairCreate', component: '/asset/repair/create/index', meta: { title: 'Repair Create', isHide: true, isHideTab: true } },
      { path: 'repair/edit/:repairId', name: 'AssetRepairEdit', component: '/asset/repair/edit/index', meta: { title: 'Repair Edit', isHide: true, isHideTab: true } },
      { path: 'repair/detail/:repairId', name: 'AssetRepairDetail', component: '/asset/repair/detail/index', meta: { title: 'Repair Detail', isHide: true, isHideTab: true } }
    ]
  }]

  const repairListRows = [{
    repairId: 1001,
    repairNo: 'R-1001',
    assetCode: 'ASSET-001',
    assetName: 'Device A',
    itemCount: 1,
    repairStatus: 'DRAFT',
    applyDeptName: 'Asset Dept',
    applyUserName: 'Admin',
    reportTime: '2026-03-28 09:00:00',
    vendorName: 'Repair Vendor',
    repairCost: 123.45,
    resultType: 'SUGGEST_DISPOSAL',
    faultDesc: 'Fault desc',
    beforeStatus: 'IN_USE',
    afterStatus: 'IN_USE'
  }]

  const repairDetail = {
    repairId: 1001,
    repairNo: 'R-1001',
    assetCode: 'ASSET-001',
    assetName: 'Device A',
    itemCount: 1,
    repairStatus: 'FINISHED',
    applyDeptName: 'Asset Dept',
    applyUserName: 'Admin',
    reportTime: '2026-03-28 09:00:00',
    vendorName: 'Repair Vendor',
    repairCost: 123.45,
    resultType: 'SUGGEST_DISPOSAL',
    faultDesc: 'Fault desc',
    remark: 'Remark',
    beforeStatus: 'IN_USE',
    afterStatus: 'IN_USE',
    approveUserName: 'Reviewer',
    approveTime: '2026-03-28 10:00:00',
    finishTime: '2026-03-28 11:30:00',
    sendRepairTime: '2026-03-28 09:30:00',
    repairMode: 'VENDOR',
    repairItems: [{
      repairItemId: 1,
      assetId: 1,
      assetCode: 'ASSET-001',
      assetName: 'Device A',
      beforeStatus: 'IN_USE',
      afterStatus: 'IN_USE',
      resultType: 'SUGGEST_DISPOSAL',
      faultDesc: 'Fault desc',
      remark: 'detail'
    }]
  }

  const userJson = JSON.stringify(userState)
  localStorage.setItem('sys-v3.0.1-user', userJson)
  localStorage.setItem('user', userJson)

  function responseFor(method, url) {
    const target = String(url || '')
    const upper = String(method || '').toUpperCase()

    if (target.includes('/getInfo')) {
      return { code: 200, data: { user: userState.info, roles: userState.roles, permissions: userState.permissions }, msg: 'ok' }
    }
    if (target.includes('/getRouters')) {
      return { code: 200, data: repairRoutes, msg: 'ok' }
    }
    if (target.includes('/asset/repair/list')) {
      return { code: 200, data: { rows: repairListRows, total: 1, current: 1, size: 10 }, msg: 'ok' }
    }
    if (/\/asset\/repair\/\d+$/.test(target) && upper === 'GET') {
      return { code: 200, data: repairDetail, msg: 'ok' }
    }
    if (target.includes('/asset/repair/submit/') || target.includes('/asset/repair/approve/') || target.includes('/asset/repair/reject/') || target.includes('/asset/repair/finish/') || target.includes('/asset/repair/cancel/')) {
      return { code: 200, data: { repairId: 1001 }, msg: 'ok' }
    }
    if (target.includes('/asset/repair') && (upper === 'POST' || upper === 'PUT' || upper === 'DELETE')) {
      return { code: 200, data: { repairId: 1001, repairNo: 'R-1001' }, msg: 'ok' }
    }
    return null
  }

  const NativeXHR = window.XMLHttpRequest
  class MockXHR {
    constructor() {
      this.readyState = 0
      this.status = 0
      this.responseText = ''
      this.response = ''
      this.responseURL = ''
      this.responseType = ''
      this.timeout = 0
      this.withCredentials = false
      this.onreadystatechange = null
      this.onload = null
      this.onloadend = null
      this.onerror = null
      this.onabort = null
      this.ontimeout = null
      this.__mockMethod = 'GET'
      this.__mockUrl = ''
      this.__listeners = new Map()
    }
    open(method, url) { this.__mockMethod = method; this.__mockUrl = url; this.responseURL = String(url); this.readyState = 1 }
    setRequestHeader() {}
    overrideMimeType() {}
    addEventListener(type, handler) { const list = this.__listeners.get(type) || []; list.push(handler); this.__listeners.set(type, list) }
    removeEventListener(type, handler) { const list = this.__listeners.get(type) || []; this.__listeners.set(type, list.filter((item) => item !== handler)) }
    getAllResponseHeaders() { return 'content-type: application/json' }
    getResponseHeader(name) { return String(name || '').toLowerCase() === 'content-type' ? 'application/json' : null }
    abort() { this.readyState = 0; this.onabort && this.onabort(); this.__dispatch('abort') }
    __dispatch(type) { (this.__listeners.get(type) || []).forEach((handler) => { try { handler.call(this, new Event(type)) } catch (error) { console.error(error) } }) }
    send() {
      const payload = responseFor(this.__mockMethod, this.__mockUrl)
      if (!payload) {
        payload = { code: 500, msg: `Mock not covered: ${this.__mockMethod} ${this.__mockUrl}` }
      }
      const responseText = JSON.stringify(payload)
      try {
        Object.defineProperty(this, 'status', { value: 200, configurable: true })
        Object.defineProperty(this, 'readyState', { value: 4, configurable: true })
        Object.defineProperty(this, 'responseURL', { value: String(this.__mockUrl || ''), configurable: true })
        Object.defineProperty(this, 'responseText', { value: responseText, configurable: true })
        Object.defineProperty(this, 'response', { value: this.responseType === 'blob' ? new Blob([responseText], { type: 'application/json' }) : responseText, configurable: true })
      } catch (error) {
        console.error(error)
      }
      setTimeout(() => { this.onreadystatechange && this.onreadystatechange(); this.onload && this.onload(); this.onloadend && this.onloadend(); this.__dispatch('readystatechange'); this.__dispatch('load'); this.__dispatch('loadend') }, 0)
    }
  }

  window.XMLHttpRequest = MockXHR
  window.__repairMockInstalled = true
  return { installed: true, nativeXHR: !!NativeXHR, userKey: 'sys-v3.0.1-user' }
})()
